+ getTradeId() : uint32_t {query}
+ getTakerOrderId() : uint64_t {query}
+ getMakerOrderId() : uint64_t {query}
+ getQuantity() : uint32_t {query}
+ getPrice() : uint32_t {query}

+ OrderBook()
